// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// admin ping (testing auth)
	// (GET /admin/ping)
	GetAdminPing(ctx context.Context, request GetAdminPingRequestObject) (GetAdminPingResponseObject, error)
	// Get admin dashboard stats
	// (GET /admin/stats)
	GetAdminStats(ctx context.Context, request GetAdminStatsRequestObject) (GetAdminStatsResponseObject, error)
	// List all users for admin panel
	// (GET /admin/users)
	GetAdminUsers(ctx context.Context, request GetAdminUsersRequestObject) (GetAdminUsersResponseObject, error)
	// Permanently delete a user and all associated data
	// (DELETE /admin/users/{userId})
	AdminDeleteUser(ctx context.Context, request AdminDeleteUserRequestObject) (AdminDeleteUserResponseObject, error)
	// Set a user's coin balance
	// (PUT /admin/users/{userId}/balance)
	AdminUpdateBalance(ctx context.Context, request AdminUpdateBalanceRequestObject) (AdminUpdateBalanceResponseObject, error)
	// Unban a user
	// (DELETE /admin/users/{userId}/ban)
	UnbanUser(ctx context.Context, request UnbanUserRequestObject) (UnbanUserResponseObject, error)
	// Ban a user
	// (PUT /admin/users/{userId}/ban)
	BanUser(ctx context.Context, request BanUserRequestObject) (BanUserResponseObject, error)
	// Change a user's display name
	// (PUT /admin/users/{userId}/display-name)
	AdminUpdateDisplayName(ctx context.Context, request AdminUpdateDisplayNameRequestObject) (AdminUpdateDisplayNameResponseObject, error)
	// Change a user's gender
	// (PUT /admin/users/{userId}/gender)
	AdminUpdateGender(ctx context.Context, request AdminUpdateGenderRequestObject) (AdminUpdateGenderResponseObject, error)
	// Change a user's password
	// (PUT /admin/users/{userId}/password)
	AdminUpdatePassword(ctx context.Context, request AdminUpdatePasswordRequestObject) (AdminUpdatePasswordResponseObject, error)
	// Change a user's username
	// (PUT /admin/users/{userId}/username)
	AdminUpdateUsername(ctx context.Context, request AdminUpdateUsernameRequestObject) (AdminUpdateUsernameResponseObject, error)
	// Check if a username is available
	// (GET /auth/check-username)
	CheckUsername(ctx context.Context, request CheckUsernameRequestObject) (CheckUsernameResponseObject, error)
	// Login
	// (POST /auth/login)
	Login(ctx context.Context, request LoginRequestObject) (LoginResponseObject, error)
	// Logout and clear refresh token cookie
	// (POST /auth/logout)
	Logout(ctx context.Context, request LogoutRequestObject) (LogoutResponseObject, error)
	// Refresh access token using refresh token cookie
	// (POST /auth/refresh)
	RefreshToken(ctx context.Context, request RefreshTokenRequestObject) (RefreshTokenResponseObject, error)
	// Register a new user
	// (POST /auth/register)
	RegisterUser(ctx context.Context, request RegisterUserRequestObject) (RegisterUserResponseObject, error)
	// Get current user balance
	// (GET /balance)
	GetBalance(ctx context.Context, request GetBalanceRequestObject) (GetBalanceResponseObject, error)
	// Claim daily reward
	// (POST /daily-reward)
	ClaimDailyReward(ctx context.Context, request ClaimDailyRewardRequestObject) (ClaimDailyRewardResponseObject, error)
	// Get hug activity for the last 24 hours grouped by hour
	// (GET /hugs/activity)
	GetHugActivity(ctx context.Context, request GetHugActivityRequestObject) (GetHugActivityResponseObject, error)
	// Check cooldown status for a user pair
	// (GET /hugs/cooldown/{userId})
	GetCooldown(ctx context.Context, request GetCooldownRequestObject) (GetCooldownResponseObject, error)
	// Upgrade (reduce) cooldown by spending balance
	// (POST /hugs/cooldown/{userId}/upgrade)
	UpgradeCooldown(ctx context.Context, request UpgradeCooldownRequestObject) (UpgradeCooldownResponseObject, error)
	// Get recent hugs feed
	// (GET /hugs/feed)
	GetHugsFeed(ctx context.Context, request GetHugsFeedRequestObject) (GetHugsFeedResponseObject, error)
	// Get hug history for current user
	// (GET /hugs/history)
	GetHugHistory(ctx context.Context, request GetHugHistoryRequestObject) (GetHugHistoryResponseObject, error)
	// Get pending incoming hug suggestions
	// (GET /hugs/inbox)
	GetHugInbox(ctx context.Context, request GetHugInboxRequestObject) (GetHugInboxResponseObject, error)
	// Get count of pending incoming suggestions
	// (GET /hugs/inbox/count)
	GetHugInboxCount(ctx context.Context, request GetHugInboxCountRequestObject) (GetHugInboxCountResponseObject, error)
	// Get current user's outgoing pending hugs and slot info
	// (GET /hugs/outgoing)
	GetOutgoingHugs(ctx context.Context, request GetOutgoingHugsRequestObject) (GetOutgoingHugsResponseObject, error)
	// Buy an additional hug suggestion slot
	// (POST /hugs/slots/buy)
	BuyHugSlot(ctx context.Context, request BuyHugSlotRequestObject) (BuyHugSlotResponseObject, error)
	// Accept a pending hug suggestion
	// (POST /hugs/{hugId}/accept)
	AcceptHug(ctx context.Context, request AcceptHugRequestObject) (AcceptHugResponseObject, error)
	// Cancel your own outgoing pending hug
	// (POST /hugs/{hugId}/cancel)
	CancelHug(ctx context.Context, request CancelHugRequestObject) (CancelHugResponseObject, error)
	// Decline a pending hug suggestion
	// (POST /hugs/{hugId}/decline)
	DeclineHug(ctx context.Context, request DeclineHugRequestObject) (DeclineHugResponseObject, error)
	// Suggest a hug to a user
	// (POST /hugs/{userId})
	SuggestHug(ctx context.Context, request SuggestHugRequestObject) (SuggestHugResponseObject, error)
	// Get leaderboard
	// (GET /leaderboard)
	GetLeaderboard(ctx context.Context, request GetLeaderboardRequestObject) (GetLeaderboardResponseObject, error)
	// Ping endpoint
	// (GET /ping)
	GetPing(ctx context.Context, request GetPingRequestObject) (GetPingResponseObject, error)
	// Get current user info
	// (GET /users/me)
	GetCurrentUser(ctx context.Context, request GetCurrentUserRequestObject) (GetCurrentUserResponseObject, error)
	// Get list of blocked users
	// (GET /users/me/blocked)
	GetBlockedUsers(ctx context.Context, request GetBlockedUsersRequestObject) (GetBlockedUsersResponseObject, error)
	// Change current user password
	// (PUT /users/me/password)
	ChangePassword(ctx context.Context, request ChangePasswordRequestObject) (ChangePasswordResponseObject, error)
	// Update current user settings
	// (PUT /users/me/settings)
	UpdateUserSettings(ctx context.Context, request UpdateUserSettingsRequestObject) (UpdateUserSettingsResponseObject, error)
	// Unlink Telegram account
	// (DELETE /users/me/telegram)
	UnlinkTelegram(ctx context.Context, request UnlinkTelegramRequestObject) (UnlinkTelegramResponseObject, error)
	// Generate a deep-link token for Telegram account linking
	// (POST /users/me/telegram/link-token)
	CreateTelegramLinkToken(ctx context.Context, request CreateTelegramLinkTokenRequestObject) (CreateTelegramLinkTokenResponseObject, error)
	// Search users by username
	// (GET /users/search)
	SearchUsers(ctx context.Context, request SearchUsersRequestObject) (SearchUsersResponseObject, error)
	// Unblock a user
	// (DELETE /users/{userId}/block)
	UnblockUser(ctx context.Context, request UnblockUserRequestObject) (UnblockUserResponseObject, error)
	// Block a user
	// (POST /users/{userId}/block)
	BlockUser(ctx context.Context, request BlockUserRequestObject) (BlockUserResponseObject, error)
	// Get user profile with stats
	// (GET /users/{userId}/profile)
	GetUserProfile(ctx context.Context, request GetUserProfileRequestObject) (GetUserProfileResponseObject, error)
}

type StrictHandlerFunc = strictecho.StrictEchoHandlerFunc
type StrictMiddlewareFunc = strictecho.StrictEchoMiddlewareFunc

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
}

// GetAdminPing operation middleware
func (sh *strictHandler) GetAdminPing(ctx echo.Context) error {
	var request GetAdminPingRequestObject

	handler := func(ctx echo.Context, request interface{}) (interface{}, error) {
		return sh.ssi.GetAdminPing(ctx.Request().Context(), request.(GetAdminPingRequestObject))
	}
	for _, middleware := range sh.middlewares {
		handler = middleware(handler, "GetAdminPing")
	}

	response, err := handler(ctx, request)

	if err != nil {
		return err
	} else if validResponse, ok := response.(GetAdminPingResponseObject); ok {
		return validResponse.VisitGetAdminPingResponse(ctx.Response())
	} else if response != nil {
		return fmt.Errorf("unexpected response type: %T", response)
	}
	return nil
}

